import { createClient } from "@/lib/supabase/client";
import type {
  ConfigurationMaterial,
  LaborCost,
  LineGlassCompatibility,
  Material,
  ProductType,
  SystemConfiguration,
  SystemLine,
} from "@/types/cotizador";
import type { EntityId } from "@/types/common";

type CotizadorCatalogoRepositoryDeps = {
  clientFactory?: ReturnType<typeof createClient>;
};

type ProductTypeRow = {
  id: EntityId;
  nombre: string;
  descripcion: string | null;
  creado_en: string | null;
};

type SystemLineRow = {
  id: EntityId;
  organization_id: EntityId | null;
  nombre: string;
  material_base: string | null;
  tipo_apertura: string | null;
  espesor_max_vidrio_mm: number | string | null;
  descripcion: string | null;
  creado_en: string | null;
};

type SystemConfigurationRow = {
  id: EntityId;
  organization_id: EntityId | null;
  product_type_id: EntityId | null;
  system_line_id: EntityId | null;
  nombre: string | null;
  descripcion: string | null;
  hojas: number | null;
  activo: boolean | null;
  creado_en: string | null;
};

type ConfigurationMaterialRow = {
  id: EntityId;
  configuration_id: EntityId;
  material_id: EntityId;
  rol_material: string | null;
  formula: string | null;
  merma_pct: number | string | null;
  requerido: boolean | null;
  orden: number | null;
  creado_en: string | null;
};

type MaterialRow = {
  id: EntityId;
  organization_id: EntityId;
  nombre: string;
  costo: number | string;
  inventario: number;
  unidad: string | null;
  categoria: string | null;
  precio_venta: number | string | null;
  material_type_id: string | null;
  creado_en: string | null;
  actualizado_en: string | null;
  eliminado_en: string | null;
};

type LaborCostRow = {
  id: EntityId;
  organization_id: EntityId;
  nombre: string | null;
  tipo: string | null;
  monto: number | string | null;
  unidad: string | null;
  activo: boolean | null;
  creado_en: string | null;
};

type LineGlassCompatibilityRow = {
  id: EntityId;
  system_line_id: EntityId;
  glass_material_id: EntityId;
  permitido: boolean | null;
  recomendado: boolean | null;
  creado_en: string | null;
};

type ConfigurationFilters = {
  organizationId: EntityId;
  productTypeId?: EntityId;
  systemLineId?: EntityId;
};

const SYSTEM_LINE_SELECT =
  "id, organization_id, nombre, material_base, tipo_apertura, espesor_max_vidrio_mm, descripcion, creado_en";
const SYSTEM_CONFIGURATION_SELECT =
  "id, organization_id, product_type_id, system_line_id, nombre, descripcion, hojas, activo, creado_en";
const CONFIGURATION_MATERIAL_SELECT =
  "id, configuration_id, material_id, rol_material, formula, merma_pct, requerido, orden, creado_en";
const MATERIAL_SELECT =
  "id, organization_id, nombre, costo, inventario, unidad, categoria, precio_venta, material_type_id, creado_en, actualizado_en, eliminado_en";
const LABOR_COST_SELECT =
  "id, organization_id, nombre, tipo, monto, unidad, activo, creado_en";

function mapProductType(row: ProductTypeRow): ProductType {
  return {
    id: row.id,
    nombre: row.nombre,
    descripcion: row.descripcion,
    creadoEn: row.creado_en,
  };
}

function mapSystemLine(row: SystemLineRow): SystemLine {
  return {
    id: row.id,
    organizationId: row.organization_id,
    nombre: row.nombre,
    materialBase: row.material_base,
    tipoApertura: row.tipo_apertura,
    espesorMaxVidrioMm:
      row.espesor_max_vidrio_mm === null ? null : Number(row.espesor_max_vidrio_mm),
    descripcion: row.descripcion,
    creadoEn: row.creado_en,
  };
}

function mapSystemConfiguration(
  row: SystemConfigurationRow
): SystemConfiguration {
  return {
    id: row.id,
    organizationId: row.organization_id,
    productTypeId: row.product_type_id,
    systemLineId: row.system_line_id,
    nombre: row.nombre,
    descripcion: row.descripcion,
    hojas: row.hojas,
    activo: row.activo ?? true,
    creadoEn: row.creado_en,
  };
}

function mapConfigurationMaterial(
  row: ConfigurationMaterialRow
): ConfigurationMaterial {
  return {
    id: row.id,
    configurationId: row.configuration_id,
    materialId: row.material_id,
    rolMaterial: row.rol_material,
    formula: row.formula,
    mermaPct: row.merma_pct === null ? 0 : Number(row.merma_pct),
    requerido: row.requerido ?? true,
    orden: row.orden ?? 0,
    creadoEn: row.creado_en,
  };
}

function mapMaterial(row: MaterialRow): Material {
  return {
    id: row.id,
    organizationId: row.organization_id,
    nombre: row.nombre,
    costo: Number(row.costo),
    inventario: row.inventario,
    unidad: row.unidad,
    categoria: row.categoria,
    precioVenta: row.precio_venta === null ? null : Number(row.precio_venta),
    materialTypeId: row.material_type_id,
    creadoEn: row.creado_en,
    actualizadoEn: row.actualizado_en,
    eliminadoEn: row.eliminado_en,
  };
}

function mapLaborCost(row: LaborCostRow): LaborCost {
  return {
    id: row.id,
    organizationId: row.organization_id,
    nombre: row.nombre,
    tipo: row.tipo,
    monto: row.monto === null ? 0 : Number(row.monto),
    unidad: row.unidad,
    activo: row.activo ?? true,
    creadoEn: row.creado_en,
  };
}

function mapLineGlassCompatibility(
  row: LineGlassCompatibilityRow
): LineGlassCompatibility {
  return {
    id: row.id,
    systemLineId: row.system_line_id,
    glassMaterialId: row.glass_material_id,
    permitido: row.permitido ?? true,
    recomendado: row.recomendado ?? false,
    creadoEn: row.creado_en,
  };
}

function buildOrganizationScope(organizationId: EntityId) {
  return `organization_id.eq.${organizationId},organization_id.is.null`;
}

export function createCotizadorCatalogoRepository(
  deps: CotizadorCatalogoRepositoryDeps = {}
) {
  const supabase = deps.clientFactory ?? createClient();

  return {
    async listProductTypes() {
      const { data, error } = await supabase
        .from("product_types")
        .select("id, nombre, descripcion, creado_en")
        .order("nombre", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as ProductTypeRow[]).map(mapProductType);
    },

    async listSystemLinesByOrganizationId(organizationId: EntityId) {
      const { data, error } = await supabase
        .from("system_lines")
        .select(SYSTEM_LINE_SELECT)
        .or(buildOrganizationScope(organizationId))
        .order("nombre", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as SystemLineRow[]).map(mapSystemLine);
    },

    async listMaterialsByOrganizationId(organizationId: EntityId) {
      const { data, error } = await supabase
        .from("materials")
        .select(MATERIAL_SELECT)
        .eq("organization_id", organizationId)
        .is("eliminado_en", null)
        .order("nombre", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as MaterialRow[]).map(mapMaterial);
    },

    async listActiveLaborCostsByOrganizationId(organizationId: EntityId) {
      const { data, error } = await supabase
        .from("labor_costs")
        .select(LABOR_COST_SELECT)
        .eq("organization_id", organizationId)
        .eq("activo", true)
        .order("nombre", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as LaborCostRow[]).map(mapLaborCost);
    },

    async listConfigurations(filters: ConfigurationFilters) {
      let query = supabase
        .from("system_configurations")
        .select(SYSTEM_CONFIGURATION_SELECT)
        .or(buildOrganizationScope(filters.organizationId))
        .eq("activo", true);

      if (filters.productTypeId !== undefined) {
        query = query.eq("product_type_id", filters.productTypeId);
      }

      if (filters.systemLineId !== undefined) {
        query = query.eq("system_line_id", filters.systemLineId);
      }

      const { data, error } = await query.order("nombre", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as SystemConfigurationRow[]).map(mapSystemConfiguration);
    },

    async listConfigurationMaterials(configurationId: EntityId) {
      const { data, error } = await supabase
        .from("configuration_materials")
        .select(CONFIGURATION_MATERIAL_SELECT)
        .eq("configuration_id", configurationId)
        .order("orden", { ascending: true });

      if (error) {
        throw error;
      }

      return (data as ConfigurationMaterialRow[]).map(mapConfigurationMaterial);
    },

    async listCompatibleGlassBySystemLineId(systemLineId: EntityId) {
      const { data, error } = await supabase
        .from("line_glass_compatibility")
        .select(
          "id, system_line_id, glass_material_id, permitido, recomendado, creado_en"
        )
        .eq("system_line_id", systemLineId);

      if (error) {
        throw error;
      }

      return (data as LineGlassCompatibilityRow[]).map(mapLineGlassCompatibility);
    },
  };
}

export type CotizadorCatalogoRepository = ReturnType<
  typeof createCotizadorCatalogoRepository
>;

export const cotizadorCatalogoRepository = createCotizadorCatalogoRepository();
